async function batchProcess(ids) {
  const results = await Promise.all(
    ids.map(id => db.query(`SELECT * FROM orders WHERE user_id = ?`, [id]))
  );
  // No pool config, no transaction boundaries
  const updates = results.flat().map(r => db.query(`UPDATE orders SET status = 'processed' WHERE id = ?`, [r.id]));
  await Promise.all(updates);
}

