import crypto from 'crypto';

async function processWebhook(req, env) {
  const signature = req.headers.get('stripe-signature');
  const payload = await req.text();
  try {
    const event = stripe.webhooks.constructEvent(payload, signature, env.WEBHOOK_SECRET);
    await db.prepare('INSERT INTO events (type, data, created_at) VALUES (?, ?, ?)').bind(event.type, payload, new Date().toISOString()).run();
    return new Response('OK');
  } catch (err) {
    return new Response('Invalid signature', { status: 400 });
  }
}

