async function migrateUsers(sourceDB, targetDB) {
  const allUsers = await sourceDB.prepare('SELECT * FROM users').all();
  await Promise.all(
    allUsers.results.map(user => 
      targetDB.prepare('INSERT INTO users (id, name, email) VALUES (?, ?, ?)')
        .bind(user.id, user.name, user.email).run()
    )
  );
  console.log(`Migrated ${allUsers.results.length} users`);
}

